const today = new Date();
const month = String(today.getMonth() + 1).padStart(2, '0');
const day = String(today.getDate()).padStart(2, '0');
return [{ json: { dateFilter: `2000-${month}-${day}` } }];

const clients = $input.first().json;
const result = [];

if (!Array.isArray(clients) || clients.length === 0) {
  console.log('Sin cumpleaños hoy');
  return [];
}

for (const c of clients) {
  const telefono = c.telefono || c.telefono_casa;
  const nombre = c.nombre || 'Cliente';

  const mensaje = `🎂 ¡Hola ${nombre}! Hoy es tu día especial y queríamos ser los primeros en celebrarlo contigo. 🎉\n\nEn Connection Worldwide Group te tenemos un regalo de cumpleaños: un bono exclusivo de $200 para tu próximo equipo Royal Prestige, válido durante este mes.\n\nSolo comunícate con nosotros al (818) 266-7038 y te damos todos los detalles para que puedas reclamarlo.\n\n¡Que tengas un cumpleaños increíble rodeado de las personas que más quieres!\n\nCon cariño,\nConnection Worldwide Group`;

  if (telefono) {
    result.push({
      json: {
        owner_id: '2e33a96f-1261-4df1-8fd2-89f3910c6558',
        org_id: '00000000-0000-0000-0000-000000000001',
        contact_tipo: 'cliente',
        contact_id: c.id,
        contexto_tipo: 'campana',
        canal: 'whatsapp',
        destinatario: telefono,
        mensaje: mensaje,
        mensaje_resuelto: mensaje,
        status: 'programado',
        scheduled_for: new Date(Date.now() - 1000).toISOString()
      }
    });
  }

  if (c.email && c.email.includes('@')) {
    const emailSubject = `🎂 ¡Feliz cumpleaños ${nombre}! Un regalo especial para ti`;
    const emailMsg = `Hola ${nombre},\n\n¡Hoy es tu día especial y queríamos ser los primeros en celebrarlo contigo! 🎉\n\nEn Connection Worldwide Group te tenemos un regalo de cumpleaños: un bono exclusivo de $200 para tu próximo equipo Royal Prestige, válido durante este mes.\n\nNo necesitas hacer nada complicado — solo comunícate con nosotros al (818) 266-7038 y coordinamos los detalles para que puedas reclamar tu regalo.\n\n¡Que tengas un cumpleaños increíble rodeado de las personas que más quieres!\n\nCon cariño,\nConnection Worldwide Group`;

    result.push({
      json: {
        owner_id: '2e33a96f-1261-4df1-8fd2-89f3910c6558',
        org_id: '00000000-0000-0000-0000-000000000001',
        contact_tipo: 'cliente',
        contact_id: c.id,
        contexto_tipo: 'campana',
        canal: 'email',
        destinatario: c.email,
        asunto: emailSubject,
        mensaje: emailMsg,
        mensaje_resuelto: emailMsg,
        from_name: 'Connection Worldwide Group',
        status: 'programado',
        scheduled_for: new Date(Date.now() - 1000).toISOString()
      }
    });
  }
}

console.log(`Cumpleaños hoy: ${clients.length} clientes, ${result.length} mensajes`);
return result;
